import android.app.Activity
import android.content.Intent
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import kotlinx.android.synthetic.main.activity_login.*
import java.util.concurrent.Executor
import kotlin.coroutines.coroutineContext

class LoginActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate()) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                // Biometric authentication is supported
                val executor: Executor = ContextCompat.getMainExecutor(this)
                val promptInfo = BiometricPrompt.PromptInfo.Builder()
                    .setTitle("Biometric Authentication")
                    .setDescription("Please authenticate using your fingerprint")
                    .setNegativeButtonText("Cancel")
                    .build()

                val biometricPrompt = BiometricPrompt(this, executor, object : BiometricPrompt.AuthenticationCallback() {
                    override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                        super.onAuthenticationError(errorCode, errString)
                        // Fallback to password
                        tvBiometricLogin.visibility = View.GONE
                        etPassword.visibility = View.VISIBLE
                        btnLogin.visibility = View.VISIBLE

                    }

                    override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                        super.onAuthenticationSucceeded(result)
                        // Store authenticated flag in SharedPreferences and bypass login screen
                        val sharedPreferences = getSharedPreferences("prefs", MODE_PRIVATE)
                        sharedPreferences.edit().putBoolean("authenticated", true).apply()
                        finish()
                    }
                })

                btnBiometricLogin.setOnClickListener {
                    biometricPrompt.authenticate(promptInfo)
                }

            }
            BiometricManager.BIOMETRIC_ERROR_TOO_MANY_FAILED_ATTEMPTS -> {
                // Too many failed attempts
                tvBiometricLogin.visibility = View.GONE
                etPassword.visibility = View.VISIBLE
                btnLogin.visibility = View.VISIBLE

            }
            else -> {
                // Biometric authentication is not supported
                tvBiometricLogin.visibility = View.GONE
                etPassword.visibility = View.VISIBLE
                btnLogin.visibility = View.VISIBLE

            }
        }

    }

}